import{_ as a}from"./chunks/dashboard.cVGQ046t.js";import{c as t,Q as o,j as i,m as r}from"./chunks/framework.BA1dEi98.js";const b=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/dashboard.md","filePath":"guide/using-librislog/dashboard.md","lastUpdated":1780166664000}'),s={name:"guide/using-librislog/dashboard.md"};function n(l,e,d,h,u,c){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>The dashboard is the first page you see after logging in. It gives you an overview of your reading activity and quick access to your current books.</p><p><img src="'+a+'" alt="Dashboard" loading="lazy"></p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>The search bar at the top of the dashboard lets you find books by title, author, or tags. The result count updates as you type and matching books appear in a dropdown below the bar.</p><ul><li><strong>Arrow keys</strong> to navigate the dropdown</li><li><strong>Enter</strong> opens the selected book&#39;s detail view; if no item is selected, it navigates to the dedicated search results page (<code>/search</code>) showing all matches</li><li><strong>Escape</strong> to close the dropdown</li><li><strong>Click the search icon</strong> to focus the input</li></ul><p>The search results page shows a full results grid with load-more pagination and the same book detail interaction as the library.</p><h2 id="currently-reading" tabindex="-1">Currently Reading <a class="header-anchor" href="#currently-reading" aria-label="Permalink to &quot;Currently Reading&quot;">​</a></h2><p>Books you marked as &quot;Currently Reading&quot; appear with progress bars showing the current page and percentage. Click a book to open the detail view and update your progress.</p><h2 id="next-suggestions" tabindex="-1">Next Suggestions <a class="header-anchor" href="#next-suggestions" aria-label="Permalink to &quot;Next Suggestions&quot;">​</a></h2><p>Books from your &quot;Want to Read&quot; list are shown as suggestions — pick one to start reading next.</p><h2 id="inspirational-quote" tabindex="-1">Inspirational Quote <a class="header-anchor" href="#inspirational-quote" aria-label="Permalink to &quot;Inspirational Quote&quot;">​</a></h2><p>A random quote is displayed at the top of the dashboard (configurable via <code>DASHBOARD_QUOTE_ENABLED</code> in <code>.env</code>).</p><h2 id="tag-cloud" tabindex="-1">Tag Cloud <a class="header-anchor" href="#tag-cloud" aria-label="Permalink to &quot;Tag Cloud&quot;">​</a></h2><p>The most common tags in your library are shown, sized by frequency. Click any tag to filter your library by it.</p><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2><p>Access the timeline page from the left navigation menu under &quot;Timeline&quot;. The timeline page shows a chronological view of your reading activity:</p><ul><li>Books started and finished</li><li>Reading progress updates</li><li>Date conflicts (when a book&#39;s start date is after its finish date)</li></ul>',18)])])}const m=t(s,[["render",n]]);export{b as __pageData,m as default};
